import logging
from lxml import etree
from datetime import datetime, timezone

logger = logging.getLogger(__name__)

SAML_PROTOCOL_NS = 'urn:oasis:names:tc:SAML:2.0:protocol'
SAML_ASSERTION_NS = 'urn:oasis:names:tc:SAML:2.0:assertion'
XMLDSIG_NS = 'http://www.w3.org/2000/09/xmldsig#'

NAMESPACES = {
    'samlp': SAML_PROTOCOL_NS,
    'saml': SAML_ASSERTION_NS,
    'ds': XMLDSIG_NS,
}


class SAMLValidationError(Exception):
    """Raised when SAML XML validation fails."""
    pass


class SAMLXMLValidator:
    """Validates SAML Response XML structure and basic constraints."""

    def __init__(self, xml_doc):
        if isinstance(xml_doc, bytes):
            self.root = etree.fromstring(xml_doc)
        elif isinstance(xml_doc, str):
            self.root = etree.fromstring(xml_doc.encode('utf-8'))
        else:
            self.root = xml_doc
        self.errors = []

    def validate(self):
        """Run all validation checks. Returns (is_valid, errors)."""
        self.errors = []
        self._validate_root_element()
        self._validate_status()
        self._validate_assertion_presence()
        self._validate_assertion_structure()
        self._validate_conditions()
        self._validate_subject()
        return len(self.errors) == 0, self.errors

    def _validate_root_element(self):
        expected_tag = f'{{{SAML_PROTOCOL_NS}}}Response'
        if self.root.tag != expected_tag:
            self.errors.append(
                f"Root element must be samlp:Response, got {self.root.tag}"
            )

        version = self.root.get('Version')
        if version != '2.0':
            self.errors.append(
                f"SAML Version must be 2.0, got {version}"
            )

        response_id = self.root.get('ID')
        if not response_id:
            self.errors.append("Response must have an ID attribute")

        issue_instant = self.root.get('IssueInstant')
        if not issue_instant:
            self.errors.append("Response must have an IssueInstant attribute")

    def _validate_status(self):
        status = self.root.find('.//samlp:Status', NAMESPACES)
        if status is None:
            self.errors.append("Response must contain a Status element")
            return

        status_code = status.find('samlp:StatusCode', NAMESPACES)
        if status_code is None:
            self.errors.append("Status must contain a StatusCode element")
            return

        status_value = status_code.get('Value', '')
        success_status = 'urn:oasis:names:tc:SAML:2.0:status:Success'
        if status_value != success_status:
            status_message = status.find('samlp:StatusMessage', NAMESPACES)
            msg = status_message.text if status_message is not None else 'No message'
            self.errors.append(
                f"SAML Response status is not Success: {status_value} - {msg}"
            )

    def _validate_assertion_presence(self):
        assertions = self.root.findall('.//saml:Assertion', NAMESPACES)
        if len(assertions) == 0:
            self.errors.append("Response must contain at least one Assertion")

    def _validate_assertion_structure(self):
        assertions = self.root.findall('.//saml:Assertion', NAMESPACES)
        for i, assertion in enumerate(assertions):
            assertion_id = assertion.get('ID')
            if not assertion_id:
                self.errors.append(f"Assertion {i} must have an ID attribute")

            version = assertion.get('Version')
            if version != '2.0':
                self.errors.append(
                    f"Assertion {i} Version must be 2.0, got {version}"
                )

            issue_instant = assertion.get('IssueInstant')
            if not issue_instant:
                self.errors.append(
                    f"Assertion {i} must have an IssueInstant attribute"
                )

            issuer = assertion.find('saml:Issuer', NAMESPACES)
            if issuer is None:
                self.errors.append(
                    f"Assertion {i} must contain an Issuer element"
                )

            authn_statements = assertion.findall(
                'saml:AuthnStatement', NAMESPACES
            )
            if len(authn_statements) == 0:
                logger.warning(
                    f"Assertion {i} does not contain an AuthnStatement"
                )

    def _validate_conditions(self):
        conditions = self.root.find('.//saml:Conditions', NAMESPACES)
        if conditions is None:
            logger.warning("No Conditions element found in assertion")
            return

        not_before = conditions.get('NotBefore')
        not_on_or_after = conditions.get('NotOnOrAfter')
        now = datetime.now(timezone.utc)

        if not_before:
            try:
                nb_time = datetime.fromisoformat(
                    not_before.replace('Z', '+00:00')
                )
                # Allow 5 minutes clock skew
                from datetime import timedelta
                if now < nb_time - timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion is not yet valid (NotBefore: {not_before})"
                    )
            except ValueError:
                self.errors.append(
                    f"Invalid NotBefore datetime format: {not_before}"
                )

        if not_on_or_after:
            try:
                noa_time = datetime.fromisoformat(
                    not_on_or_after.replace('Z', '+00:00')
                )
                from datetime import timedelta
                if now >= noa_time + timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion has expired (NotOnOrAfter: {not_on_or_after})"
                    )
            except ValueError:
                self.errors.append(
                    f"Invalid NotOnOrAfter datetime format: {not_on_or_after}"
                )

    def _validate_subject(self):
        subject = self.root.find('.//saml:Subject', NAMESPACES)
        if subject is None:
            self.errors.append("Assertion must contain a Subject element")
            return

        name_id = subject.find('saml:NameID', NAMESPACES)
        if name_id is None or not name_id.text:
            self.errors.append(
                "Subject must contain a NameID with a value"
            )


# saml_auth/parser.py
import base64
import logging
import zlib
from lxml import etree
from defusedxml import ElementTree as DefusedET
from io import BytesIO

from .xml_validator import (
    SAMLXMLValidator,
    SAMLValidationError,
    NAMESPACES,
    SAML_ASSERTION_NS,
)

logger = logging.getLogger(__name__)


class SAMLResponseParser:
    """Parses SAML POST Response and extracts user information."""

    def __init__(self, saml_response_b64, attribute_mapping=None):
        self.raw_b64 = saml_response_b64
        self.attribute_mapping = attribute_mapping or {}
        self.xml_doc = None
        self.root = None
        self.name_id = None
        self.name_id_format = None
        self.session_index = None
        self.attributes = {}
        self.mapped_attributes = {}
        self.issuer = None

    def decode_response(self):
        """Decode base64 SAML response."""
        try:
            xml_bytes = base64.b64decode(self.raw_b64)
        except Exception as e:
            raise SAMLValidationError(f"Failed to base64 decode SAML response: {e}")

        # Try to decompress if it's deflated (some IdPs do this even for POST)
        try:
            xml_bytes = zlib.decompress(xml_bytes, -15)
        except zlib.error:
            pass  # Not compressed, use as-is

        # Use defusedxml to prevent XXE attacks during initial parse check
        try:
            DefusedET.fromstring(xml_bytes)
        except Exception as e:
            raise SAMLValidationError(f"XML security check failed: {e}")

        # Parse with lxml for full XPath support
        try:
            parser = etree.XMLParser(
                remove_blank_text=True,
                resolve_entities=False,
                no_network=True,
            )
            self.root = etree.fromstring(xml_bytes, parser=parser)
            self.xml_doc = xml_bytes
        except etree.XMLSyntaxError as e:
            raise SAMLValidationError(f"Invalid XML in SAML response: {e}")

        return self

    def validate(self):
        """Validate the SAML XML structure."""
        if self.root is None:
            raise SAMLValidationError("Must decode response before validating")

        validator = SAMLXMLValidator(self.root)
        is_valid, errors = validator.validate()

        if not is_valid:
            error_msg = "; ".join(errors)
            logger.error(f"SAML validation failed: {error_msg}")
            raise SAMLValidationError(f"SAML validation failed: {error_msg}")

        return self

    def parse(self):
        """Parse user information from the SAML assertion."""
        if self.root is None:
            raise SAMLValidationError("Must decode response before parsing")

        self._extract_issuer()
        self._extract_name_id()
        self._extract_session_index()
        self._extract_attributes()
        self._map_attributes()

        return self

    def _extract_issuer(self):
        """Extract the Issuer from the response."""
        issuer_elem = self.root.find('saml:Issuer', NAMESPACES)
        if issuer_elem is not None and issuer_elem.text:
            self.issuer = issuer_elem.text.strip()
        else:
            # Try assertion-level issuer
            issuer_elem = self.root.find(
                './/saml:Assertion/saml:Issuer', NAMESPACES
            )
            if issuer_elem is not None and issuer_elem.text:
                self.issuer = issuer_elem.text.strip()

    def _extract_name_id(self):
        """Extract NameID from the Subject."""
        name_id_elem = self.root.find(
            './/saml:Assertion/saml:Subject/saml:NameID', NAMESPACES
        )
        if name_id_elem is None:
            # Try without full path
            name_id_elem = self.root.find('.//saml:NameID', NAMESPACES)

        if name_id_elem is not None:
            self.name_id = name_id_elem.text.strip() if name_id_elem.text else None
            self.name_id_format = name_id_elem.get('Format', '')
        else:
            raise SAMLValidationError("No NameID found in SAML assertion")

        if not self.name_id:
            raise SAMLValidationError("NameID is empty")

    def _extract_session_index(self):
        """Extract SessionIndex from AuthnStatement."""
        authn_stmt = self.root.find(
            './/saml:Assertion/saml:AuthnStatement', NAMESPACES
        )
        if authn_stmt is not None:
            self.session_index = authn_stmt.get('SessionIndex')

    def _extract_attributes(self):
        """Extract all attributes from the AttributeStatement."""
        self.attributes = {}

        attr_statements = self.root.findall(
            './/saml:Assertion/saml:AttributeStatement', NAMESPACES
        )

        for attr_stmt in attr_statements:
            attrs = attr_stmt.findall('saml:Attribute', NAMESPACES)
            for attr in attrs:
                attr_name = attr.get('Name', '')
                attr_friendly_name = attr.get('FriendlyName', '')

                values = []
                for value_elem in attr.findall('saml:AttributeValue', NAMESPACES):
                    if value_elem.text:
                        values.append(value_elem.text.strip())

                # Store by Name
                if attr_name:
                    if len(values) == 1:
                        self.attributes[attr_name] = values[0]
                    elif len(values) > 1:
                        self.attributes[attr_name] = values
                    else:
                        self.attributes[attr_name] = ''

                # Also store by FriendlyName if available
                if attr_friendly_name:
                    if len(values) == 1:
                        self.attributes[attr_friendly_name] = values[0]
                    elif len(values) > 1:
                        self.attributes[attr_friendly_name] = values
                    else:
                        self.attributes[attr_friendly_name] = ''

        logger.debug(f"Extracted SAML attributes: {self.attributes}")

    def _map_attributes(self):
        """Map SAML attributes to Django user fields using attribute_mapping."""
        self.mapped_attributes = {}

        for saml_attr, django_field in self.attribute_mapping.items():
            if saml_attr in self.attributes:
                value = self.attributes[saml_attr]
                if isinstance(value, list):
                    value = value[0] if value else ''
                self.mapped_attributes[django_field] = value

        logger.debug(f"Mapped attributes: {self.mapped_attributes}")

    def get_user_data(self):
        """Return a dictionary of user information."""
        return {
            'name_id': self.name_id,
            'name_id_format': self.name_id_format,
            'session_index': self.session_index,
            'issuer': self.issuer,
            'attributes': self.attributes,
            'mapped_attributes': self.mapped_attributes,
        }


# saml_auth/backends.py
import logging
from django.contrib.auth import get_user_model
from django.contrib.auth.backends import BaseBackend

logger = logging.getLogger(__name__)
User = get_user_model()


class SAMLAuthenticationBackend(BaseBackend):
    """Custom authentication backend for SAML-based login."""

    def authenticate(self, request, saml_user_data=None, **kwargs):
        if saml_user_data is None:
            return None

        name_id = saml_user_data.get('name_id')
        if not name_id:
            logger.error("No NameID in SAML user data")
            return None

        mapped = saml_user_data.get('mapped_attributes', {})

        # Try to find existing user by email or username
        email = mapped.get('email', '')
        username = self._generate_username(name_id, email)

        user = self._get_or_create_user(username, email, mapped, name_id)
        return user

    def _generate_username(self, name_id, email):
        """Generate a username from NameID or email."""
        if email:
            # Use email prefix as username
            username = email.split('@')[0]
        else:
            # Sanitize NameID for use as username
            username = name_id.replace('@', '_at_').replace('.', '_')

        # Truncate to fit Django's default max_length
        return username[:150]

    def _get_or_create_user(self, username, email, mapped_attrs, name_id):
        """Get existing user or create a new one."""
        user = None

        # First try to find by email
        if email:
            try:
                user = User.objects.get(email=email)
                logger.info(f"Found existing user by email: {email}")
            except User.DoesNotExist:
                pass
            except User.MultipleObjectsReturned:
                user = User.objects.filter(email=email).first()
                logger.warning(f"Multiple users found with email: {email}")

        # Then try by username
        if user is None:
            try:
                user = User.objects.get(username=username)
                logger.info(f"Found existing user by username: {username}")
            except User.DoesNotExist:
                pass

        # Create new user if not found
        if user is None:
            user = self._create_user(username, email, mapped_attrs)
            logger.info(f"Created new SAML user: {username}")
        else:
            # Update existing user attributes
            self._update_user(user, mapped_attrs)

        return user

    def _create_user(self, username, email, mapped_attrs):
        """Create a new Django user from SAML attributes."""
        # Handle username conflicts
        base_username = username
        counter = 1
        while User.objects.filter(username=username).exists():
            username = f"{base_username}_{counter}"
            counter += 1

        user = User.objects.create_user(
            username=username,
            email=email or f"{username}@saml.local",
            first_name=mapped_attrs.get('first_name', ''),
            last_name=mapped_attrs.get('last_name', ''),
        )
        # Set unusable password since auth is via SAML
        user.set_unusable_password()
        user.save()
        return user

    def _update_user(self, user, mapped_attrs):
        """Update user attributes from SAML assertion."""
        updated = False

        if 'first_name' in mapped_attrs and mapped_attrs['first_name']:
            if user.first_name != mapped_attrs['first_name']:
                user.first_name = mapped_attrs['first_name']
                updated = True

        if 'last_name' in mapped_attrs and mapped_attrs['last_name']:
            if user.last_name != mapped_attrs['last_name']:
                user.last_name = mapped_attrs['last_name']
                updated = True

        if 'email' in mapped_attrs and mapped_attrs['email']:
            if user.email != mapped_attrs['email']:
                user.email = mapped_attrs['email']
                updated = True

        if updated:
            user.save()
            logger.info(f"Updated user attributes for: {user.username}")

    def get_user(self, user_id):
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None


