import logging
import uuid
from datetime import datetime, timezone
from urllib.parse import quote

from django.conf import settings
from django.contrib import auth
from django.contrib.auth.decorators import login_required
from django.http import HttpResponse, HttpResponseBadRequest, HttpResponseRedirect
from django.shortcuts import redirect, render
from django.urls import reverse
from django.utils.decorators import method_decorator
from django.views import View
from django.views.decorators.csrf import csrf_exempt
from django.views.decorators.http import require_POST

from .models import SAMLSession
from .parser import SAMLResponseParser
from .xml_validator import SAMLValidationError

logger = logging.getLogger(__name__)


def get_saml_config():
    """Retrieve SAML configuration from Django settings."""
    config = getattr(settings, 'SAML_SP_CONFIG', {})
    if not config:
        raise SAMLValidationError("SAML_SP_CONFIG not found in Django settings")
    return config


class SAMLLoginView(View):
    """Initiate SAML login by redirecting to IdP."""

    def get(self, request):
        config = get_saml_config()
        idp_sso_url = config.get('idp_sso_url')
        entity_id = config.get('entity_id')
        acs_url = config.get('acs_url')

        if not idp_sso_url:
            return HttpResponseBadRequest("IdP SSO URL not configured")

        # Generate AuthnRequest ID
        request_id = f"_saml_{uuid.uuid4().hex}"

        # Store request ID in session for InResponseTo validation
        request.session['saml_request_id'] = request_id
        request.session['saml_relay_state'] = request.GET.get('next', '/')

        # Build AuthnRequest
        authn_request = self._build_authn_request(
            request_id, entity_id, acs_url, idp_sso_url
        )

        import base64
        encoded_request = base64.b64encode(authn_request.encode('utf-8')).decode('utf-8')

        # Build redirect URL with SAMLRequest parameter
        relay_state = request.GET.get('next', '/')
        redirect_url = (
            f"{idp_sso_url}?SAMLRequest={quote(encoded_request)}"
            f"&RelayState={quote(relay_state)}"
        )

        # Return auto-submitting form for POST binding
        context = {
            'idp_sso_url': idp_sso_url,
            'saml_request': encoded_request,
            'relay_state': relay_state,
        }
        return render(request, 'saml_auth/login_redirect.html', context)

    def _build_authn_request(self, request_id, entity_id, acs_url, destination):
        """Build a SAML AuthnRequest XML."""
        issue_instant = datetime.now(timezone.utc).strftime('%Y-%m-%dT%H:%M:%SZ')
        return f'''<?xml version="1.0" encoding="UTF-8"?>
<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{destination}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>'''


@method_decorator(csrf_exempt, name='dispatch')
class SAMLACSView(View):
    """Assertion Consumer Service - handles SAML POST Response from IdP."""

    def post(self, request):
        saml_response_b64 = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '/')

        if not saml_response_b64:
            logger.error("No SAMLResponse found in POST data")
            return HttpResponseBadRequest("Missing SAMLResponse")

        try:
            # Get SAML configuration
            config = get_saml_config()
            attribute_mapping = config.get('attribute_mapping', {})

            # Parse and validate SAML response
            parser = SAMLResponseParser(saml_response_b64, attribute_mapping)
            parser.decode_response()
            parser.validate()
            parser.parse()

            user_data = parser.get_user_data()

            logger.info(
                f"SAML authentication successful for NameID: {user_data['name_id']}"
            )

            # Authenticate user through Django's auth system
            user = auth.authenticate(
                request,
                saml_user_data=user_data,
            )

            if user is None:
                logger.error("SAML authentication backend returned None")
                return render(
                    request,
                    'saml_auth/error.html',
                    {'error': 'Authentication failed. Unable to create or find user.'},
                    status=403,
                )

            if not user.is_active:
                logger.warning(f"Inactive user attempted SAML login: {user.username}")
                return render(
                    request,
                    'saml_auth/error.html',
                    {'error': 'Your account is inactive. Contact an administrator.'},
                    status=403,
                )

            # Log the user in and create Django session
            auth.login(request, user, backend='saml_auth.backends.SAMLAuthenticationBackend')

            # Store SAML session information
            saml_session = SAMLSession.objects.create(
                user=user,
                session_index=user_data.get('session_index', ''),
                name_id=user_data['name_id'],
                name_id_format=user_data.get('name_id_format', ''),
                idp_entity_id=user_data.get('issuer', ''),
                attributes=user_data.get('attributes', {}),
            )

            # Store SAML session ID in Django session
            request.session['saml_session_id'] = saml_session.id
            request.session['saml_name_id'] = user_data['name_id']
            request.session['saml_session_index'] = user_data.get('session_index', '')

            logger.info(
                f"User {user.username} logged in via SAML. "
                f"Session index: {user_data.get('session_index')}"
            )

            # Redirect to RelayState or default
            if relay_state and relay_state.startswith('/'):
                return HttpResponseRedirect(relay_state)
            return HttpResponseRedirect('/')

        except SAMLValidationError as e:
            logger.error(f"SAML validation error: {e}")
            return render(
                request,
                'saml_auth/error.html',
                {'error': f'SAML validation error: {str(e)}'},
                status=400,
            )
        except Exception as e:
            logger.exception(f"Unexpected error processing SAML response: {e}")
            return render(
                request,
                'saml_auth/error.html',
                {'error': 'An unexpected error occurred during authentication.'},
                status=500,
            )


class SAMLLogoutView(View):
    """Handle SAML logout."""

    def get(self, request):
        return self._logout(request)

    def post(self, request):
        return self._logout(request)

    def _logout(self, request):
        # Clean up SAML session
        saml_session_id = request.session.get('saml_session_id')
        if saml_session_id:
            try:
                saml_session = SAMLSession.objects.get(id=saml_session_id)
                saml_session.delete()
            except SAMLSession.DoesNotExist:
                pass

        # Django logout
        auth.logout(request)

        logger.info("User logged out via SAML logout")

        # Optionally redirect to IdP SLO
        config = get_saml_config()
        idp_slo_url = config.get('idp_slo_url')
        if idp_slo_url:
            return HttpResponseRedirect(idp_slo_url)

        return redirect('saml_login')


class SAMLMetadataView(View):
    """Serve SP metadata XML."""

    def get(self, request):
        config = get_saml_config()
        entity_id = config.get('entity_id', '')
        acs_url = config.get('acs_url', '')

        metadata = f'''<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="1"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>'''

        return HttpResponse(metadata, content_type='application/xml')


