# saml_auth/middleware.py
import logging
from django.utils.deprecation import MiddlewareMixin

logger = logging.getLogger(__name__)


class SAMLSessionMiddleware(MiddlewareMixin):
    """Middleware to validate SAML sessions on each request."""

    def process_request(self, request):
        if not hasattr(request, 'session'):
            return None

        if not request.user.is_authenticated:
            return None

        saml_session_id = request.session.get('saml_session_id')
        if saml_session_id:
            from .models import SAMLSession
            from datetime import datetime, timezone
            try:
                saml_session = SAMLSession.objects.get(id=saml_session_id)
                # Check if session has expired
                if saml_session.expires_at and saml_session.expires_at < datetime.now(timezone.utc):
                    logger.info(
                        f"SAML session expired for user {request.user.username}"
                    )
                    from django.contrib import auth
                    auth.logout(request)
            except SAMLSession.DoesNotExist:
                # SAML session was deleted (e.g., SLO), log out
                logger.info(
                    f"SAML session not found for user {request.user.username}"
                )
                from django.contrib import auth
                auth.logout(request)

        return None


