# Management command for template creation
# saml_auth/management/__init__.py
# saml_auth/management/commands/__init__.py
# saml_auth/management/commands/setup_saml_templates.py
import os
from django.core.management.base import BaseCommand
from django.conf import settings


class Command(BaseCommand):
    help = 'Create SAML authentication templates'

    def handle(self, *args, **options):
        template_dir = os.path.join(
            settings.BASE_DIR, 'saml_auth', 'templates', 'saml_auth'
        )
        os.makedirs(template_dir, exist_ok=True)

        templates = {
            'login_redirect.html': LOGIN_REDIRECT_TEMPLATE,
            'error.html': ERROR_TEMPLATE,
        }

        for filename, content in templates.items():
            filepath = os.path.join(template_dir, filename)
            with open(filepath, 'w') as f:
                f.write(content)
            self.stdout.write(f"Created {filepath}")

        self.stdout.write(self.style.SUCCESS('SAML templates created successfully'))


# saml_auth/tests.py
import base64
import json
from datetime import datetime, timezone, timedelta
from unittest.mock import patch, MagicMock

from django.contrib.auth import get_user_model
from django.test import TestCase, RequestFactory, override_settings
from django.test.client import Client

from .parser import SAMLResponseParser
from .xml_validator import SAMLXMLValidator, SAMLValidationError
from .backends import SAMLAuthenticationBackend
from .models import SAMLSession

User = get_user_model()

SAML_TEST_CONFIG = {
    'entity_id': 'https://sp.example.com/saml/metadata/',
    'acs_url': 'https://sp.example.com/saml/acs/',
    'idp_entity_id': 'https://idp.example.com/',
    'idp_sso_url': 'https://idp.example.com/sso/saml',
    'attribute_mapping': {
        'User.email': 'email',
        'User.FirstName': 'first_name',
        'User.LastName': 'last_name',
    },
    'want_assertions_signed': False,
    'allow_unsolicited': True,
}


def build_saml_response(
    name_id='user@example.com',
    email='user@example.com',
    first_name='Test',
    last_name='User',
    status='urn:oasis:names:tc:SAML:2.0:status:Success',
    not_before=None,
    not_on_or_after=None,
    session_index='_session_123',
    issuer='https://idp.example.com/',
    include_assertion=True,
):
    """Build a test SAML response XML."""
    now = datetime.now(timezone.utc)
    if not_before is None:
        not_before = (now - timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    if not_on_or_after is None:
        not_on_or_after = (now + timedelta(hours=1)).strftime('%Y-%m-%dT%H:%M:%SZ')

    issue_instant = now.strftime('%Y-%m-%dT%H:%M:%SZ')

    assertion_xml = ''
    if include_assertion:
        assertion_xml = f'''
    <saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
        ID="_assertion_123" Version="2.0" IssueInstant="{issue_instant}">
        <saml:Issuer>{issuer}</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">
                {name_id}
            </saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData
                    NotOnOrAfter="{not_on_or_after}"
                    Recipient="https://sp.example.com/saml/acs/"/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>https://sp.example.com/saml/metadata/</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="{session_index}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>
                    urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport
                </saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>
            <saml:Attribute Name="User.email">
                <saml:AttributeValue>{email}</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="User.FirstName">
                <saml:AttributeValue>{first_name}</saml:AttributeValue>
            </saml:Attribute>
            <saml:Attribute Name="User.LastName">
                <saml:AttributeValue>{last_name}</saml:AttributeValue>
            </saml:Attribute>
        </saml:AttributeStatement>
    </saml:Assertion>'''

    xml = f'''<?xml version="1.0" encoding="UTF-8"?>
<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="_response_456" Version="2.0" IssueInstant="{issue_instant}"
    Destination="https://sp.example.com/saml/acs/">
    <saml:Issuer>{issuer}</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="{status}"/>
    </samlp:Status>
    {assertion_xml}
</samlp:Response>'''

    return xml


def encode_saml_response(xml):
    """Base64 encode a SAML response."""
    return base64.b64encode(xml.encode('utf-8')).decode('utf-8')


class SAMLXMLValidatorTest(TestCase):
    """Tests for SAML XML structure validation."""

    def test_valid_response(self):
        xml = build_saml_response()
        validator = SAMLXMLValidator(xml.encode('utf-8'))
        is_valid, errors = validator.validate()
        self.assertTrue(is_valid, f"Validation errors: {errors}")

    def test_missing_assertion(self):
        xml = build_saml_response(include_assertion=False)
        validator = SAMLXMLValidator(xml.encode('utf-8'))
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)
        self.assertTrue(any('Assertion' in e for e in errors))

    def test_failed_status(self):
        xml = build_saml_response(
            status='urn:oasis:names:tc:SAML:2.0:status:Requester'
        )
        validator = SAMLXMLValidator(xml.encode('utf-8'))
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)
        self.assertTrue(any('not Success' in e for e in errors))

    def test_expired_assertion(self):
        past = (datetime.now(timezone.utc) - timedelta(hours=2)).strftime(
            '%Y-%m-%dT%H:%M:%SZ'
        )
        xml = build_saml_response(
            not_before=(datetime.now(timezone.utc) - timedelta(hours=3)).strftime(
                '%Y-%m-%dT%H:%M:%SZ'
            ),
            not_on_or_after=past,
        )
        validator = SAMLXMLValidator(xml.encode('utf-8'))
        is_valid, errors = validator.validate()
        self.assertFalse(is_valid)
        self.assertTrue(any('expired' in e for e in errors))


class SAMLResponseParserTest(TestCase):
    """Tests for SAML response parsing."""

    def test_parse_valid_response(self):
        xml = build_saml_response(
            name_id='testuser@example.com',
            email='testuser@example.com',
            first_name='Test',
            last_name='User',
        )
        encoded = encode_saml_response(xml)

        parser = SAMLResponseParser(encoded, SAML_TEST_CONFIG['attribute_mapping'])
        parser.decode_response()
        parser.validate()
        parser.parse()

        user_data = parser.get_user_data()
        self.assertEqual(user_data['name_id'], 'testuser@example.com')
        self.assertEqual(user_data['mapped_attributes']['email'], 'testuser@example.com')
        self.assertEqual(user_data['mapped_attributes']['first_name'], 'Test')
        self.assertEqual(user_data['mapped_attributes']['last_name'], 'User')
        self.assertEqual(user_data['session_index'], '_session_123')

    def test_parse_invalid_base64(self):
        parser = SAMLResponseParser('not-valid-base64!!!')
        with self.assertRaises(SAMLValidationError):
            parser.decode_response()

    def test_parse_invalid_xml(self):
        encoded = base64.b64encode(b'<not valid xml').decode('utf-8')
        parser = SAMLResponseParser(encoded)
        with self.assertRaises(SAMLValidationError):
            parser.decode_response()


class SAMLAuthenticationBackendTest(TestCase):
    """Tests for the SAML authentication backend."""

    def setUp(self):
        self.backend = SAMLAuthenticationBackend()
        self.factory = RequestFactory()

    def test_authenticate_creates_new_user(self):
        request = self.factory.get('/')
        request.session = {}

        user_data = {
            'name_id': 'newuser@example.com',
            'mapped_attributes': {
                'email': 'newuser@example.com',
                'first_name': 'New',
                'last_name': 'User',
            },
        }

        user = self.backend.authenticate(request, saml_user_data=user_data)
        self.assertIsNotNone(user)
        self.assertEqual(user.email, 'newuser@example.com')
        self.assertEqual(user.first_name, 'New')
        self.assertEqual(user.last_name, 'User')
        self.assertFalse(user.has_usable_password())

    def test_authenticate_finds_existing_user(self):
        existing_user = User.objects.create_user(
            username='existing',
            email='existing@example.com',
            first_name='Old',
            last_name='Name',
        )

        request = self.factory.get('/')
        request.session = {}

        user_data = {
            'name_id': 'existing@example.com',
            'mapped_attributes': {
                'email': 'existing@example.com',
                'first_name': 'Updated',
                'last_name': 'Name',
            },
        }

        user = self.backend.authenticate(request, saml_user_data=user_data)
        self.assertIsNotNone(user)
        self.assertEqual(user.pk, existing_user.pk)
        user.refresh_from_db()
        self.assertEqual(user.first_name, 'Updated')

    def test_authenticate_without_saml_data(self):
        request = self.factory.get('/')
        user = self.backend.authenticate(request)
        self.assertIsNone(user)

    def test_authenticate_without_name_id(self):
        request = self.factory.get('/')
        user_data = {'name_id': '', 'mapped_attributes': {}}
        user = self.backend.authenticate(request, saml_user_data=user_data)
        self.assertIsNone(user)


@override_settings(SAML_SP_CONFIG=SAML_TEST_CONFIG)
class SAMLViewTest(TestCase):
    """Tests for SAML views."""

    def setUp(self):
        self.client = Client()

    def test_acs_missing_saml_response(self):
        response = self.client.post('/saml/acs/')
        self.assertEqual(response.status_code, 400)

    def test_acs_valid_response(self):
        xml = build_saml_response(
            name_id='viewuser@example.com',
            email='viewuser@example.com',
            first_name='View',
            last_name='User',
        )
        encoded = encode_saml_response(xml)

        response = self.client.post('/saml/acs/', {
            'SAMLResponse': encoded,
            'RelayState': '/dashboard/',
        })

        self.assertEqual(response.status_code, 302)
        self.assertEqual(response.url, '/dashboard/')

        # Verify user was created
        user = User.objects.get(email='viewuser@example.com')
        self.assertEqual(user.first_name, 'View')
        self.assertEqual(user.last_name, 'User')

        # Verify SAML session was created
        saml_session = SAMLSession.objects.get(user=user)
        self.assertEqual(saml_session.name_id, 'viewuser@example.com')

    def test_acs_invalid_saml_response(self):
        encoded = base64.b64encode(b'<invalid/>').decode('utf-8')
        response = self.client.post('/saml/acs/', {
            'SAMLResponse': encoded,
        })
        self.assertEqual(response.status_code, 400)

    def test_metadata_endpoint(self):
        response = self.client.get('/saml/metadata/')
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response['Content-Type'], 'application/xml')
        self.assertIn(b'EntityDescriptor', response.content)

    def test_login_view(self):
        response = self.client.get('/saml/login/')
        self.assertEqual(response.status_code, 200)
        self.assertIn(b'SAMLRequest', response.content)

    def test_logout_view(self):
        # Create and login a user first
        user = User.objects.create_user(
            username='logouttest', email='logout@example.com'
        )
        self.client.force_login(user)

        session = self.client.session
        saml_session = SAMLSession.objects.create(
            user=user,
            name_id='logout@example.com',
            session_index='_session_456',
        )
        session['saml_session_id'] = saml_session.id
        session.save()

        response = self.client.get('/saml/logout/')
        self.assertEqual(response.status_code, 302)

        # Verify SAML session was cleaned up
        self.assertFalse(SAMLSession.objects.filter(id=saml_session.id).exists())